from __future__ import annotations

import base64
import zlib
from pathlib import Path

TARGET = Path("Livre-II/CHAPITRE-16-Famille-et-generations.md")
PAYLOAD = """"""

raw = zlib.decompress(base64.b64decode(PAYLOAD))
text = raw.decode("utf-8")
assert 'status: "reviewed"' in text
assert 'version: "1.0.0"' in text
assert 'audit-status: "complete"' in text
assert 'audit-report: "Livre-II/QA/AUDIT-CHAPITRE-16.md"' in text
assert text.count("<!-- qa:error-correction-section -->") == 1
TARGET.write_text(text, encoding="utf-8", newline="\n")
print(f"Wrote {TARGET} with {len(text.splitlines())} lines")
